from __future__ import annotations

import weakref


class ObjectRegistry:
    def __init__(self):
        self.refs = {}
        self.tags = {}

    def register(self, key: str, obj, tags=None):
        self.refs[key] = weakref.ref(obj)
        for tag in tags or set():
            self.tags.setdefault(tag, []).append(key)

    def get(self, key: str):
        ref = self.refs.get(key)
        return None if ref is None else ref()

    def cleanup(self):
        self.refs = {key: ref for key, ref in self.refs.items() if ref() is not None}

    def by_tag(self, tag: str):
        out = []
        for key in self.tags.get(tag, []):
            value = self.get(key)
            if value is not None:
                out.append(value)
        return out

